#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int minSubArrayLen(int target, vector<int> &nums)
{
    int n = nums.size();
    int best = INT_MAX;

    for (int i = 0; i < n; i++)
    {
        int sum = 0;
        for (int j = i; j < n; j++)
        {
            sum += nums[j];
            if (sum >= target)
            {
                best = min(best, j - i + 1);
                break;
            }
        }
    }

    return (best == INT_MAX) ? 0 : best;
}

int main()
{
    vector<int> nums = {2, 3, 1, 2, 4, 3};

    cout << minSubArrayLen(7, nums) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int minSubArrayLen(int target, vector<int> &nums)
{
    int left = 0;
    int sum = 0;
    int best = INT_MAX;

    for (int right = 0; right < nums.size(); right++)
    {
        sum += nums[right];

        while (sum >= target)
        {
            best = min(best, right - left + 1);
            sum -= nums[left];
            left++;
        }
    }

    return (best == INT_MAX) ? 0 : best;
}

int main()
{
    vector<int> nums = {2, 3, 1, 2, 4, 3};

    cout << minSubArrayLen(7, nums) << endl;

    return 0;
}

