bool hasRepeat(string &s, int i, int j)
{
    unordered_set<char> seen;
    for (int k = i; k <= j; k++)
    {
        if (seen.count(s[k])) return true;
        seen.insert(s[k]);
    }
    return false;
}

int lengthOfLongestSubstring(string s)
{
    int best = 0;

    for (int i = 0; i < s.size(); i++)
    {
        for (int j = i; j < s.size(); j++)
        {
            if (!hasRepeat(s, i, j)) best = max(best, j - i + 1);
        }
    }

    return best;
}

