bool checkInclusion(string s1, string s2)
{
    int k = s1.size();
    string sortedS1 = s1;
    sort(sortedS1.begin(), sortedS1.end());

    for (int i = 0; i + k <= (int)s2.size(); i++)
    {
        string window = s2.substr(i, k);
        sort(window.begin(), window.end());
        if (window == sortedS1) return true;
    }

    return false;
}

int main()
{
    cout << (checkInclusion("ab", "eidbaooo") ? "true" : "false") << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>

using namespace std;

bool checkInclusion(string s1, string s2)
{
    int k = s1.size();
    if (k > (int)s2.size()) return false;

    vector<int> need(26, 0), window(26, 0);
    for (char c : s1) need[c - 'a']++;

    for (int i = 0; i < k; i++) window[s2[i] - 'a']++;
    if (window == need) return true;

    for (int i = k; i < (int)s2.size(); i++)
    {
        window[s2[i] - 'a']++;
        window[s2[i - k] - 'a']--;
        if (window == need) return true;
    }

    return false;
}

int main()
{
    cout << (checkInclusion("ab", "eidbaooo") ? "true" : "false") << endl;

    return 0;
}

