vector<int> findAnagrams(string s, string p)
{
    vector<int> result;
    int k = p.size();
    string sortedP = p;
    sort(sortedP.begin(), sortedP.end());

    for (int i = 0; i + k <= (int)s.size(); i++)
    {
        string window = s.substr(i, k);
        sort(window.begin(), window.end());
        if (window == sortedP) result.push_back(i);
    }

    return result;
}

int main()
{
    vector<int> result = findAnagrams("cbaebabacd", "abc");
    for (int r : result) cout << r << " ";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>

using namespace std;

vector<int> findAnagrams(string s, string p)
{
    vector<int> result;
    int k = p.size();
    if (k > (int)s.size()) return result;

    vector<int> need(26, 0), window(26, 0);
    for (char c : p) need[c - 'a']++;

    for (int i = 0; i < k; i++) window[s[i] - 'a']++;
    if (window == need) result.push_back(0);

    for (int i = k; i < (int)s.size(); i++)
    {
        window[s[i] - 'a']++;
        window[s[i - k] - 'a']--;
        if (window == need) result.push_back(i - k + 1);
    }

    return result;
}

int main()
{
    vector<int> result = findAnagrams("cbaebabacd", "abc");
    for (int r : result) cout << r << " ";

    return 0;
}

