using namespace std;

int characterReplacement(string s, int k)
{
    int best = 0;

    for (int i = 0; i < s.size(); i++)
    {
        vector<int> counts(26, 0);
        int maxFreq = 0;

        for (int j = i; j < s.size(); j++)
        {
            counts[s[j] - 'A']++;
            maxFreq = max(maxFreq, counts[s[j] - 'A']);

            int windowLen = j - i + 1;
            if (windowLen - maxFreq <= k) best = max(best, windowLen);
        }
    }

    return best;
}

int main()
{
    cout << characterReplacement("ABAB", 2) << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>

using namespace std;

int characterReplacement(string s, int k)
{
    vector<int> counts(26, 0);
    int left = 0;
    int maxFreq = 0;
    int best = 0;

    for (int right = 0; right < s.size(); right++)
    {
        counts[s[right] - 'A']++;
        maxFreq = max(maxFreq, counts[s[right] - 'A']);

        int windowLen = right - left + 1;
        if (windowLen - maxFreq > k)
        {
            counts[s[left] - 'A']--;
            left++;
        }

        best = max(best, right - left + 1);
    }

    return best;
}

int main()
{
    cout << characterReplacement("ABAB", 2) << endl;

    return 0;
}

